import React, { useRef, useEffect, useCallback, useMemo, useState } from 'react';
import styled from 'styled-components';

const Canvas = styled.canvas`
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  opacity: 0.6;
`;


const ParticleField = React.memo(() => {
  const canvasRef = useRef(null);
  const animationRef = useRef();
  const particlesRef = useRef([]);
  const mouseRef = useRef({ x: 0, y: 0 });
  const lastFrameTime = useRef(0);
  const [isVisible, setIsVisible] = useState(true);
  const [performanceMode, setPerformanceMode] = useState('normal');
  
  // Detect device performance
  useEffect(() => {
    const checkPerformance = () => {
      const memory = performance.memory?.usedJSHeapSize || 0;
      const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
      const isLowEnd = navigator.hardwareConcurrency <= 4 || memory > 500000000 || isMobile;
      
      setPerformanceMode(isLowEnd ? 'low' : 'normal');
    };
    
    checkPerformance();
  }, []);
  
  // Handle visibility changes
  useEffect(() => {
    const handleVisibilityChange = () => {
      setIsVisible(!document.hidden);
    };
    
    document.addEventListener('visibilitychange', handleVisibilityChange);
    
    const observer = new IntersectionObserver(
      ([entry]) => {
        setIsVisible(entry.isIntersecting);
      },
      { threshold: 0.1 }
    );
    
    if (canvasRef.current) {
      observer.observe(canvasRef.current);
    }
    
    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      observer.disconnect();
    };
  }, []);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    
    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
    
    // Initialize particles with performance-based count
    const isMobileDevice = window.innerWidth <= 768;
    const baseDivisor = performanceMode === 'low' ? 40000 : (isMobileDevice ? 25000 : 15000);
    const particleCount = Math.min(Math.floor((canvas.width * canvas.height) / baseDivisor), 
      performanceMode === 'low' ? 30 : (isMobileDevice ? 50 : 100));
    const particles = [];
    
    for (let i = 0; i < particleCount; i++) {
      particles.push({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        vx: (Math.random() - 0.5) * 0.5,
        vy: (Math.random() - 0.5) * 0.5,
        radius: Math.random() * 2 + 1,
        color: Math.random() > 0.5 ? '#9945ff' : '#c77dff',
        alpha: Math.random() * 0.5 + 0.5,
        targetAlpha: Math.random() * 0.5 + 0.5,
        connections: []
      });
    }
    
    particlesRef.current = particles;
    
    // Throttled mouse move handler
    let mouseThrottle = null;
    const handleMouseMove = (e) => {
      if (!mouseThrottle) {
        mouseThrottle = setTimeout(() => {
          mouseRef.current = { x: e.clientX, y: e.clientY };
          mouseThrottle = null;
        }, 16); // ~60fps for mouse updates
      }
    };
    
    window.addEventListener('mousemove', handleMouseMove, { passive: true });
    
    // FPS-limited animation loop
    const targetFPS = performanceMode === 'low' ? 30 : 60;
    const frameInterval = 1000 / targetFPS;
    
    const animate = (currentTime) => {
      if (!isVisible) {
        animationRef.current = requestAnimationFrame(animate);
        return;
      }
      
      const deltaTime = currentTime - lastFrameTime.current;
      
      if (deltaTime > frameInterval) {
        lastFrameTime.current = currentTime - (deltaTime % frameInterval);
        
        ctx.clearRect(0, 0, canvas.width, canvas.height);
      
      particles.forEach((particle, i) => {
        // Update position
        particle.x += particle.vx;
        particle.y += particle.vy;
        
        // Bounce off edges
        if (particle.x < 0 || particle.x > canvas.width) particle.vx *= -1;
        if (particle.y < 0 || particle.y > canvas.height) particle.vy *= -1;
        
        // Mouse interaction
        const dx = mouseRef.current.x - particle.x;
        const dy = mouseRef.current.y - particle.y;
        const distance = Math.sqrt(dx * dx + dy * dy);
        
        if (distance < 100) {
          const force = (100 - distance) / 100;
          particle.vx -= (dx / distance) * force * 0.02;
          particle.vy -= (dy / distance) * force * 0.02;
          particle.targetAlpha = 1;
        } else {
          particle.targetAlpha = Math.random() * 0.5 + 0.5;
        }
        
        // Smooth alpha transition
        particle.alpha += (particle.targetAlpha - particle.alpha) * 0.1;
        
        // Draw particle
        ctx.beginPath();
        ctx.arc(particle.x, particle.y, particle.radius, 0, Math.PI * 2);
        ctx.fillStyle = particle.color;
        ctx.globalAlpha = particle.alpha;
        ctx.fill();
        
        // Draw connections (optimized for performance)
        if (performanceMode === 'normal' || i < 20) {
          const maxConnections = performanceMode === 'low' ? 2 : 5;
          let connections = 0;
          
          for (let j = i + 1; j < particles.length && connections < maxConnections; j++) {
            const otherParticle = particles[j];
            const dx = otherParticle.x - particle.x;
            const dy = otherParticle.y - particle.y;
            const distance = Math.sqrt(dx * dx + dy * dy);
            
            if (distance < 120) {
              ctx.beginPath();
              ctx.moveTo(particle.x, particle.y);
              ctx.lineTo(otherParticle.x, otherParticle.y);
              ctx.strokeStyle = particle.color;
              ctx.globalAlpha = (1 - distance / 120) * particle.alpha * 0.3;
              ctx.lineWidth = 0.5;
              ctx.stroke();
              connections++;
            }
          }
        }
      });
      }
      
      animationRef.current = requestAnimationFrame(animate);
    };
    
    animationRef.current = requestAnimationFrame(animate);
    
    return () => {
      window.removeEventListener('resize', resizeCanvas);
      window.removeEventListener('mousemove', handleMouseMove);
      if (mouseThrottle) clearTimeout(mouseThrottle);
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [isVisible, performanceMode]);
  
  return <Canvas ref={canvasRef} />;
});

ParticleField.displayName = 'ParticleField';

export default ParticleField;