import React, { useEffect, useRef } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import gsap from 'gsap';
import { TextPlugin } from 'gsap/TextPlugin';

gsap.registerPlugin(TextPlugin);

const TitleContainer = styled.div`
  position: relative;
  margin-bottom: var(--space-2xl);
  min-width: 420px; /* Accommodate longest text "INNOVATOR" */
  
  @media (max-width: 1024px) {
    min-width: 360px;
  }
  
  @media (max-width: 768px) {
    min-width: unset; /* Allow natural width on mobile */
  }
`;

const MainTitle = styled(motion.h1)`
  font-size: var(--text-6xl);
  font-weight: 900;
  line-height: 1.1;
  background: linear-gradient(135deg, var(--color-light-purple) 0%, var(--color-neon-purple) 50%, var(--color-electric-violet) 100%);
  background-clip: text;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-size: 200% auto;
  animation: gradientShift 8s ease infinite;
  position: relative;
  transform: none !important;
  
  @media (max-width: 1024px) {
    font-size: var(--text-5xl);
  }
  
  @media (max-width: 768px) {
    font-size: clamp(2.5rem, 10vw, 3.5rem);
  }
  
  @media (max-width: 480px) {
    font-size: clamp(2rem, 12vw, 3rem);
  }
`;

const GlitchTitle = styled.h1`
  position: absolute;
  top: 0;
  left: 0;
  font-size: var(--text-6xl);
  font-weight: 900;
  line-height: 1.1;
  color: var(--color-neon-purple);
  opacity: 0;
  pointer-events: none;
  
  @media (max-width: 1024px) {
    font-size: var(--text-5xl);
  }
  
  @media (max-width: 768px) {
    font-size: clamp(2.5rem, 10vw, 3.5rem);
  }
  
  @media (max-width: 480px) {
    font-size: clamp(2rem, 12vw, 3rem);
  }
`;



const AnimatedTitle = () => {
  const titleRef = useRef(null);
  const glitchRef1 = useRef(null);
  const glitchRef2 = useRef(null);
  
  useEffect(() => {
    const titles = ['KENSHIN13', 'DEVELOPER', 'FREELANCER', 'PROBLEM SOLVER', 'INNOVATOR'];
    let currentIndex = 0;
    
    const animateTitle = () => {
      if (!titleRef.current) return;
      
      // Move to next title FIRST (except for the very first run)
      if (currentIndex !== 0 || titleRef.current.textContent !== 'KENSHIN13') {
        currentIndex = (currentIndex + 1) % titles.length;
      }
      
      // Get current title
      const currentTitle = titles[currentIndex];
      const firstLetter = currentTitle.charAt(0);
      
      const timeline = gsap.timeline({
        onComplete: () => {
          setTimeout(animateTitle, 2000);
        }
      });
      
      // Update glitch text to current title
      if (glitchRef1.current && glitchRef2.current) {
        glitchRef1.current.textContent = currentTitle;
        glitchRef2.current.textContent = currentTitle;
      }
      
      // Glitch effect
      timeline.to([glitchRef1.current, glitchRef2.current], {
        opacity: 1,
        duration: 0.1,
        ease: "power2.inOut",
        repeat: 3,
        yoyo: true,
        onUpdate: function() {
          if (glitchRef1.current && glitchRef2.current) {
            glitchRef1.current.style.transform = `translate(${Math.random() * 4 - 2}px, ${Math.random() * 4 - 2}px)`;
            glitchRef2.current.style.transform = `translate(${Math.random() * 4 - 2}px, ${Math.random() * 4 - 2}px)`;
            glitchRef1.current.style.textShadow = `${Math.random() * 4 - 2}px 0 var(--color-electric-violet)`;
            glitchRef2.current.style.textShadow = `${Math.random() * 4 - 2}px 0 var(--color-neon-purple)`;
          }
        }
      });
      
      // Typewriter effect - keep first letter
      timeline.to(titleRef.current, {
        duration: 0.5,
        text: firstLetter,
        ease: "none",
      });
      
      timeline.to(titleRef.current, {
        duration: 1,
        text: currentTitle,
        ease: "none",
      });
    };
    
    // Start animation after a short delay
    const timer = setTimeout(animateTitle, 1000);
    
    return () => {
      clearTimeout(timer);
      // Clean up any ongoing animations
      gsap.killTweensOf(titleRef.current);
      gsap.killTweensOf(glitchRef1.current);
      gsap.killTweensOf(glitchRef2.current);
    };
  }, []);
  
  return (
    <TitleContainer>
      <MainTitle ref={titleRef}>
        KENSHIN13
      </MainTitle>
      <GlitchTitle ref={glitchRef1}></GlitchTitle>
      <GlitchTitle ref={glitchRef2} style={{ color: 'var(--color-electric-violet)' }}>
      </GlitchTitle>
    </TitleContainer>
  );
};

export default AnimatedTitle;