import React, { useEffect, useState } from 'react';
import styled, { keyframes } from 'styled-components';
import { motion, AnimatePresence } from 'framer-motion';
import logoImage from '../../assets/img/logo.png';

const zoomExplosion = keyframes`
  0% {
    transform: scale(15) translateZ(1000px);
    opacity: 0;
    filter: blur(20px);
  }
  30% {
    transform: scale(8) translateZ(500px);
    opacity: 0.5;
    filter: blur(10px);
  }
  60% {
    transform: scale(3) translateZ(200px);
    opacity: 0.8;
    filter: blur(5px);
  }
  85% {
    transform: scale(0.8) translateZ(0);
    opacity: 1;
    filter: blur(0);
  }
  90% {
    transform: scale(1.1) translateZ(0);
    opacity: 1;
    filter: blur(0) brightness(2);
  }
  95% {
    transform: scale(0.95) translateZ(0);
    opacity: 1;
    filter: blur(0) brightness(1);
  }
  100% {
    transform: scale(1) translateZ(0);
    opacity: 1;
    filter: blur(0) brightness(1);
  }
`;

const glitchEffect = keyframes`
  0% {
    transform: translate(0, 0) scale(1);
    filter: none;
  }
  10% {
    transform: translate(-2px, 2px) scale(1.01);
    filter: hue-rotate(90deg) saturate(2);
  }
  20% {
    transform: translate(2px, -2px) scale(0.99);
    filter: hue-rotate(-90deg) saturate(2);
  }
  30% {
    transform: translate(-1px, 1px) scale(1.01);
    filter: hue-rotate(180deg) saturate(3);
  }
  40% {
    transform: translate(1px, -1px) scale(0.99);
    filter: hue-rotate(270deg) saturate(2);
  }
  50% {
    transform: translate(-2px, 0) scale(1.02);
    filter: hue-rotate(45deg) saturate(2.5);
  }
  60% {
    transform: translate(2px, 1px) scale(0.98);
    filter: hue-rotate(-45deg) saturate(2);
  }
  70% {
    transform: translate(0, -2px) scale(1.01);
    filter: hue-rotate(135deg) saturate(3);
  }
  80% {
    transform: translate(-1px, 2px) scale(0.99);
    filter: hue-rotate(-135deg) saturate(2);
  }
  90% {
    transform: translate(1px, -1px) scale(1);
    filter: hue-rotate(60deg) saturate(2);
  }
  100% {
    transform: translate(0, 0) scale(1);
    filter: none;
  }
`;

const shockwave = keyframes`
  0% {
    width: 0;
    height: 0;
    opacity: 1;
  }
  60% {
    width: 150vmax;
    height: 150vmax;
    opacity: 0.3;
  }
  100% {
    width: 300vmax;
    height: 300vmax;
    opacity: 0;
  }
`;

const screenShake = keyframes`
  0%, 100% {
    transform: translate(0, 0);
  }
  10% {
    transform: translate(-10px, 10px);
  }
  20% {
    transform: translate(10px, -10px);
  }
  30% {
    transform: translate(-10px, -10px);
  }
  40% {
    transform: translate(10px, 10px);
  }
  50% {
    transform: translate(-5px, 5px);
  }
  60% {
    transform: translate(5px, -5px);
  }
  70% {
    transform: translate(-2px, 2px);
  }
  80% {
    transform: translate(2px, -2px);
  }
`;

const flashWhite = keyframes`
  0% {
    opacity: 0;
  }
  50% {
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
`;

const dataGlitch = keyframes`
  0%, 100% {
    content: 'KENSHIN13';
    opacity: 1;
  }
  10% {
    content: 'K3N5H1N13';
    opacity: 0.8;
  }
  20% {
    content: '▓▒░▓▒░▓▒░';
    opacity: 0.9;
  }
  30% {
    content: 'KEN▓▒░N13';
    opacity: 0.7;
  }
  40% {
    content: '010011010';
    opacity: 0.8;
  }
  50% {
    content: 'K█NS█IN█3';
    opacity: 0.9;
  }
  60% {
    content: 'KENSHIN13';
    opacity: 0.7;
  }
  70% {
    content: '█▓▒░▓▒░█';
    opacity: 0.8;
  }
  80% {
    content: 'K3N5H1N13';
    opacity: 0.9;
  }
  90% {
    content: 'KENSH▓N13';
    opacity: 0.8;
  }
`;

const LoadingContainer = styled(motion.div)`
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background: #000;
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  perspective: 1000px;
  animation: ${props => props.$shake ? screenShake : 'none'} 0.5s ease-out;
`;

const LogoContainer = styled.div`
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  transform-style: preserve-3d;
`;

const LogoImage = styled.img`
  height: 120px;
  width: auto;
  animation: 
    ${zoomExplosion} 1s cubic-bezier(0.11, 0, 0.5, 0) forwards,
    ${props => props.$glitch ? glitchEffect : 'none'} 0.3s linear;
  animation-delay: 0s, 1s;
  filter: drop-shadow(0 0 50px rgba(153, 69, 255, 1));
  position: relative;
  z-index: 2;
  
  @media (max-width: 768px) {
    height: 100px;
  }
`;

const GlitchText = styled.div`
  position: absolute;
  bottom: -40px;
  left: 50%;
  transform: translateX(-50%);
  font-size: 14px;
  font-family: 'Courier New', monospace;
  color: var(--color-neon-purple);
  letter-spacing: 3px;
  opacity: ${props => props.$show ? 1 : 0};
  transition: opacity 0.1s;
  
  &::before {
    content: 'KENSHIN13';
    animation: ${props => props.$show ? dataGlitch : 'none'} 0.3s steps(10);
  }
`;

const GlitchOverlay = styled.div`
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  opacity: ${props => props.$show ? 1 : 0};
  mix-blend-mode: screen;
  
  &::before {
    content: '';
    position: absolute;
    top: -5px;
    left: -5px;
    right: -5px;
    bottom: -5px;
    background: url(${logoImage}) center/120px no-repeat;
    filter: hue-rotate(180deg) blur(1px);
    animation: ${glitchEffect} 0.3s linear;
    opacity: 0.5;
  }
  
  &::after {
    content: '';
    position: absolute;
    top: 5px;
    left: 5px;
    right: 5px;
    bottom: 5px;
    background: url(${logoImage}) center/120px no-repeat;
    filter: hue-rotate(90deg) blur(1px);
    animation: ${glitchEffect} 0.3s linear reverse;
    opacity: 0.5;
  }
`;

const ShockWave = styled.div`
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  border-radius: 50%;
  border: 3px solid var(--color-neon-purple);
  animation: ${shockwave} 0.8s cubic-bezier(0, 0.5, 0.5, 1) forwards;
  animation-delay: 0.7s;
  pointer-events: none;
  z-index: 1;
  box-shadow: 
    0 0 50px var(--color-neon-purple),
    inset 0 0 50px var(--color-neon-purple);
`;

const ShockWave2 = styled(ShockWave)`
  animation-delay: 0.75s;
  border-width: 1px;
  opacity: 0.5;
`;

const ShockWave3 = styled(ShockWave)`
  animation-delay: 0.8s;
  border-width: 1px;
  opacity: 0.3;
`;



const ExplosionParticle = styled.div`
  position: absolute;
  width: 4px;
  height: 4px;
  background: var(--color-neon-purple);
  border-radius: 50%;
  top: 50%;
  left: 50%;
  animation: ${props => props.$animation} 1s cubic-bezier(0, 0.5, 0.5, 1) forwards;
  animation-delay: 0.7s;
  opacity: 0;
  box-shadow: 0 0 10px var(--color-neon-purple);
`;

const particleExplosion = (x, y) => keyframes`
  0% {
    transform: translate(-50%, -50%);
    opacity: 1;
  }
  100% {
    transform: translate(calc(-50% + ${x}px), calc(-50% + ${y}px));
    opacity: 0;
  }
`;

const LoadingScreen = ({ onLoadingComplete }) => {
  const [isLoading, setIsLoading] = useState(true);
  const [shake, setShake] = useState(false);
  const [glitch, setGlitch] = useState(false);
  const [showGlitchText, setShowGlitchText] = useState(false);
  
  useEffect(() => {
    // Trigger shake effect at impact
    const shakeTimer = setTimeout(() => {
      setShake(true);
    }, 700);
    
    // Trigger glitch effect after landing
    const glitchTimer = setTimeout(() => {
      setGlitch(true);
      setShowGlitchText(true);
      
      // Stop glitch after animation
      setTimeout(() => {
        setGlitch(false);
        setShowGlitchText(false);
      }, 300);
    }, 1000);
    
    // Complete loading after glitch
    const completeTimer = setTimeout(() => {
      setIsLoading(false);
      setTimeout(() => {
        onLoadingComplete && onLoadingComplete();
      }, 200);
    }, 1400);
    
    return () => {
      clearTimeout(shakeTimer);
      clearTimeout(glitchTimer);
      clearTimeout(completeTimer);
    };
  }, [onLoadingComplete]);
  
  // Generate explosion particles
  const particles = Array.from({ length: 20 }, (_, i) => {
    const angle = (i / 20) * Math.PI * 2;
    const distance = 200 + Math.random() * 300;
    const x = Math.cos(angle) * distance;
    const y = Math.sin(angle) * distance;
    return { id: i, x, y };
  });
  
  return (
    <AnimatePresence>
      {isLoading && (
        <LoadingContainer
          $shake={shake}
          initial={{ opacity: 1 }}
          exit={{ 
            opacity: 0,
            scale: 1.05,
            filter: "brightness(2) blur(10px)"
          }}
          transition={{ 
            duration: 0.3, 
            ease: [0.11, 0, 0.5, 0] 
          }}
        >
          <LogoContainer>
            <LogoImage 
              src={logoImage} 
              alt="Kenshin13"
              width="120"
              height="120"
              $glitch={glitch}
            />
            <GlitchOverlay $show={glitch} />
            <GlitchText $show={showGlitchText} />
            <ShockWave />
            <ShockWave2 />
            <ShockWave3 />
            {particles.map(particle => (
              <ExplosionParticle
                key={particle.id}
                $animation={particleExplosion(particle.x, particle.y)}
              />
            ))}
          </LogoContainer>
        </LoadingContainer>
      )}
    </AnimatePresence>
  );
};

export default LoadingScreen;