import React, { useEffect, useRef, useState } from 'react';
import styled from 'styled-components';

const Canvas = styled.canvas`
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 9998;
`;

const MouseTrail = React.memo(() => {
  const canvasRef = useRef(null);
  const mouseRef = useRef({ x: 0, y: 0 });
  const trailRef = useRef([]);
  const lastFrameTime = useRef(0);
  const [isVisible, setIsVisible] = useState(true);
  const [isEnabled, setIsEnabled] = useState(true);
  
  // Check if reduced motion is preferred
  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-reduced-motion: reduce)');
    setIsEnabled(!mediaQuery.matches);
    
    const handleChange = (e) => setIsEnabled(!e.matches);
    mediaQuery.addEventListener('change', handleChange);
    
    return () => mediaQuery.removeEventListener('change', handleChange);
  }, []);
  
  // Handle visibility changes
  useEffect(() => {
    const handleVisibilityChange = () => {
      setIsVisible(!document.hidden);
    };
    
    document.addEventListener('visibilitychange', handleVisibilityChange);
    
    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, []);
  
  useEffect(() => {
    if (!isEnabled) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animationFrameId;
    
    // Set canvas size
    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
    
    // Throttled mouse move handler
    let lastMoveTime = 0;
    const handleMouseMove = (e) => {
      const now = Date.now();
      if (now - lastMoveTime > 16) { // ~60fps
        mouseRef.current = { x: e.clientX, y: e.clientY };
        lastMoveTime = now;
      }
    };
    
    window.addEventListener('mousemove', handleMouseMove, { passive: true });
    
    // FPS-limited animation loop
    const targetFPS = 30; // Lower FPS for trail effect
    const frameInterval = 1000 / targetFPS;
    
    const animate = (currentTime) => {
      if (!isVisible || !isEnabled) {
        animationFrameId = requestAnimationFrame(animate);
        return;
      }
      
      const deltaTime = currentTime - lastFrameTime.current;
      
      if (deltaTime > frameInterval) {
        lastFrameTime.current = currentTime - (deltaTime % frameInterval);
        
        ctx.clearRect(0, 0, canvas.width, canvas.height);
      
      // Add current mouse position to trail
      trailRef.current.push({
        x: mouseRef.current.x,
        y: mouseRef.current.y,
        life: 1.0
      });
      
      // Keep trail length manageable (reduced for performance)
      const maxTrailLength = 15;
      if (trailRef.current.length > maxTrailLength) {
        trailRef.current.shift();
      }
      
      // Draw trail
      ctx.strokeStyle = '#b974ff';
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      
      for (let i = 0; i < trailRef.current.length; i++) {
        const point = trailRef.current[i];
        const nextPoint = trailRef.current[i + 1];
        
        if (nextPoint) {
          const progress = i / trailRef.current.length;
          ctx.globalAlpha = progress * 0.6; // Reduced opacity
          ctx.lineWidth = progress * 2 + 0.5; // Thinner lines
          
          ctx.beginPath();
          ctx.moveTo(point.x, point.y);
          
          // Smooth curve to next point
          const cp1x = point.x + (nextPoint.x - point.x) * 0.5;
          const cp1y = point.y + (nextPoint.y - point.y) * 0.5;
          
          ctx.quadraticCurveTo(cp1x, cp1y, nextPoint.x, nextPoint.y);
          ctx.stroke();
        }
        
        // Faster decay for shorter trail
        point.life -= 0.03;
        if (point.life <= 0) {
          trailRef.current.splice(i, 1);
          i--;
        }
      }
      }
      
      animationFrameId = requestAnimationFrame(animate);
    };
    
    animationFrameId = requestAnimationFrame(animate);
    
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('resize', resizeCanvas);
      cancelAnimationFrame(animationFrameId);
    };
  }, [isVisible, isEnabled]);
  
  return isEnabled ? <Canvas ref={canvasRef} /> : null;
});

MouseTrail.displayName = 'MouseTrail';

export default MouseTrail;